'use server';

import { serverFindShortCode, serverSaveLink } from '@lib/db';
import { Prisma } from '@lib/generated/prisma/client';
import { generateSlug, validateAndNormalizeUrl } from '@lib/helpers';

export async function createShortLink(prevState: any, formData: FormData) {
  const longUrl = formData.get('url') as string;
  const siteUrl = process.env.SITE_URL || 'http://localhost:3000';
  let validUrl = '';
  try {
    validUrl = validateAndNormalizeUrl(longUrl, siteUrl);
  } catch (e) {
    console.log(e);
    return {
      success: false,
      shortCode: null,
      error: e instanceof Error ? e.message : 'Invalid URL1',
    };
    //console.log(e);
    // zod error or string
  }
  const originalDBEntry = await serverFindShortCode(validUrl);
  if (originalDBEntry)
    return {
      success: true,
      shortCode: originalDBEntry.shortCode,
      error: null,
    };

  //Trying generation of ShortCode
  for (let i = 0; i < 3; i++) {
    //generate shortLink
    const shortCode = generateSlug();
    // check URl in db
    try {
      const newLink = await serverSaveLink(validUrl, shortCode);
      return { success: true, shortCode: newLink.shortCode, error: null };
    } catch (e) {
      if (
        !(
          e instanceof Prisma.PrismaClientKnownRequestError &&
          e.code === 'P2002'
        )
      )
        throw e;

      // Else The shortCode exist already
    }
  }
  return {
    success: false,
    error: 'Could not generate unique shortCode after 3 attempts',
  };
}
