'use client';

import { useActionState } from 'react';
import { createShortLink } from './actions';

export default function Home() {
  const [state, formAction, isPending] = useActionState(createShortLink, {
    success: false,
    error: '',
  });
  const siteUrl = process.env.SITE_URL || 'http://localhost:3000';

  return (
    <main className="flex flex-col items-center p-24">
      <h1 className="text-4xl font-bold mb-8">Next.js Shortener</h1>

      <form action={formAction}>
        <input
          type="text"
          name="url"
          placeholder="Enter a long link"
          className="p-2 boreder rounded text-black w-80"
          required
        />
        <button
          type="submit"
          disabled={isPending}
          className="bg-blue-500 text-white px-4 py-2 rounded disabled:bg-gray-400"
        >
          {isPending ? 'Saving...' : 'Save'}
        </button>
      </form>

      {state.error && <p className="text-red-500 mt-4">{state.error}</p>}

      {state.success && (
        <div className="mt-6 p-4 bg-green-100 rounded text-green-800">
          <p>Your shorted link:</p>
          <a
            href={`${siteUrl}/${state.shortCode}`}
            target="_blank"
            rel="noreferrer"
          >
            {siteUrl}/{state.shortCode}
          </a>
        </div>
      )}
    </main>
  );
}
